var items = $input.all();
var results = [];
var now = new Date().toISOString();
var today = now.substring(0, 10);

for (var i = 0; i < items.length; i++) {
  var data = items[i].json;
  var title = data.title || data.name || 'Untitled';
  var link = data.link || data.url || data.guid || '';
  var summary = data.contentSnippet || data.content || data.description || '';
  var source = data.creator || data.author || 'Unknown';
  var published = data.pubDate || data.isoDate || data.date || now;
  var category = 'funding-watch';

  // Strip HTML from summary
  summary = summary.replace(/<[^>]*>/g, '').trim();

  // Categorise based on content
  var text = (title + ' ' + summary).toLowerCase();
  if (text.indexOf('film') >= 0 || text.indexOf('screen') >= 0 || text.indexOf('script') >= 0 || text.indexOf('writer') >= 0 || text.indexOf('bfi') >= 0 || text.indexOf('creative') >= 0) {
    category = 'film-opps';
  } else if (text.indexOf('education') >= 0 || text.indexOf('course') >= 0 || text.indexOf('university') >= 0 || text.indexOf('student') >= 0 || text.indexOf('higher education') >= 0) {
    category = 'future-horizons';
  } else if (text.indexOf('startup') >= 0 || text.indexOf('entrepreneur') >= 0 || text.indexOf('innovation') >= 0 || text.indexOf('enterprise') >= 0) {
    category = 'funding-watch';
  }

  // Truncate summary
  if (summary.length > 500) {
    summary = summary.substring(0, 497) + '...';
  }

  results.push({
    json: {
      title: title,
      url: link,
      summary: summary,
      source: source,
      published: published,
      discovered_at: now,
      category: category,
      opp_type: 'funding'
    }
  });
}

// Deduplicate by URL
var seen = {};
var unique = [];
for (var j = 0; j < results.length; j++) {
  var u = results[j].json.url;
  if (u && !seen[u]) {
    seen[u] = true;
    unique.push(results[j]);
  }
}

return unique;

var items = $input.all();
var now = new Date().toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

// Get items from the categorise node (2 steps back)
var allItems = $('Categorise & Dedupe').all();

// Group by category
var groups = {};
for (var i = 0; i < allItems.length; i++) {
  var cat = allItems[i].json.category || 'other';
  if (!groups[cat]) groups[cat] = [];
  groups[cat].push(allItems[i].json);
}

var labels = {
  'funding-watch': 'Funding & Grants',
  'future-horizons': 'Education & Enterprise',
  'film-opps': 'Film & Screenwriting',
  'career-opps': 'Career Opportunities',
  'other': 'Other'
};

var html = '<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;">';
html += '<h1 style="color:#2c3e50;">Workhorse Daily Digest</h1>';
html += '<p style="color:#666;">' + now + ' &bull; ' + allItems.length + ' items scanned</p><hr style="border:1px solid #eee;">';

var cats = Object.keys(groups);
for (var c = 0; c < cats.length; c++) {
  var catKey = cats[c];
  var entries = groups[catKey];
  html += '<h2 style="color:#34495e;border-bottom:2px solid #3498db;padding-bottom:5px;">' + (labels[catKey] || catKey) + ' (' + entries.length + ')</h2>';
  html += '<ul style="list-style:none;padding:0;">';
  for (var e = 0; e < entries.length; e++) {
    html += '<li style="margin-bottom:12px;padding:10px;background:#f9f9f9;border-radius:5px;">';
    html += '<strong><a href="' + entries[e].url + '" style="color:#2980b9;text-decoration:none;">' + entries[e].title + '</a></strong>';
    if (entries[e].summary) {
      html += '<br><span style="color:#555;font-size:0.9em;">' + entries[e].summary.substring(0, 250) + '</span>';
    }
    html += '<br><small style="color:#999;">Source: ' + entries[e].source + '</small>';
    html += '</li>';
  }
  html += '</ul>';
}

html += '<hr style="border:1px solid #eee;"><p style="color:#999;font-size:0.8em;">Generated by Workhorse MacBook Server &bull; ' + now + '</p>';
html += '</div>';

return [{ json: {
  subject: 'Workhorse Daily Digest - ' + now,
  html: html,
  itemCount: allItems.length
}}];
